# Create SNS client
sns = boto3.client('sns', region_name=AWS_REGION)

def lambda_handler(event, context):
    # Get the object from S3 event
    s3_bucket_name = event['Records'][0]['s3']['bucket']['name']
    s3_object_key = event['Records'][0]['s3']['object']['key']

    try:
        # Download image from S3
        s3 = boto3.client('s3', region_name=AWS_REGION)
        response = s3.get_object(Bucket=s3_bucket_name, Key=s3_object_key)

        # Process the image here (e.g. resize, compress, etc.)
        # For this example, we just return a success message
        output_file_path = 'processed_' + s3_object_key
        with open(output_file_path, 'wb') as f:
            f.write(response['Body'].read())

        # Upload processed image back to S3
        s3.upload_file(output_file_path, BUCKET_NAME, 'processed/' + os.path.basename(s3_object_key))

    except ClientError as e:
        logging.error(e)

    # Send notification via SNS
    try:
        sns.publish(
            TopicArn='arn:aws:sns:'+AWS_REGION+':your-account-id:S3NotificationTopic',
            Message='Image uploaded to bucket ' + BUCKET_NAME,
            Subject='S3 Upload Notification'
        )
    except ClientError as e:
        logging.error(e)

    return {
        'statusCode': 200,
        'statusMessage': 'OK'
    }